-- ===== 2. ENRIQUECER por CPF (preenche apenas campos vazios) =====
update contacts c set
  cpf = coalesce(nullif(c.cpf,''), s.cpf),
  rg = coalesce(nullif(c.rg,''), s.rg),
  nome_mae = coalesce(nullif(c.nome_mae,''), s.nome_mae),
  nome_pai = coalesce(nullif(c.nome_pai,''), s.nome_pai),
  esp_benef = coalesce(nullif(c.esp_benef,''), s.esp_benef),
  nb_mat = coalesce(nullif(c.nb_mat,''), s.nb_mat),
  orgao_siape = coalesce(nullif(c.orgao_siape,''), s.orgao_siape),
  recebimento_beneficio = coalesce(nullif(c.recebimento_beneficio,''), s.recebimento_beneficio),
  banco = coalesce(nullif(c.banco,''), s.banco),
  agencia = coalesce(nullif(c.agencia,''), s.agencia),
  conta = coalesce(nullif(c.conta,''), s.conta),
  nome_rep_legal = coalesce(nullif(c.nome_rep_legal,''), s.nome_rep_legal),
  cpf_rep_legal = coalesce(nullif(c.cpf_rep_legal,''), s.cpf_rep_legal),
  rua = coalesce(nullif(c.rua,''), s.rua),
  numero = coalesce(nullif(c.numero,''), s.numero),
  bairro = coalesce(nullif(c.bairro,''), s.bairro),
  cidade = coalesce(nullif(c.cidade,''), s.cidade),
  uf = coalesce(nullif(c.uf,''), s.uf),
  cep = coalesce(nullif(c.cep,''), s.cep),
  contexto_conversa = coalesce(nullif(c.contexto_conversa,''), s.contexto_conversa),
  resumo_emprestimos = coalesce(nullif(c.resumo_emprestimos,''), s.resumo_emprestimos),
  email = coalesce(nullif(c.email,''), s.email),
  qualificacao = coalesce(nullif(c.qualificacao,''), s.qualificacao),
  aquisicao = coalesce(nullif(c.aquisicao,''), s.aquisicao),
  convenio = coalesce(nullif(c.convenio,''), s.convenio),
  status = coalesce(nullif(c.status,''), s.status),
  exp_rg = coalesce(c.exp_rg, nullif(s.exp_rg,'')::date),
  data_nasc = coalesce(c.data_nasc, nullif(s.data_nasc,'')::date),
  data_nasc_rl = coalesce(c.data_nasc_rl, nullif(s.data_nasc_rl,'')::date),
  lembrete_op = coalesce(c.lembrete_op, nullif(s.lembrete_op,'')::timestamptz),
  updated_at = now()
from stg_notion_clientes s
where s.cpf_n is not null
  and regexp_replace(coalesce(c.cpf,''),'\D','','g') = s.cpf_n;

