  lembrete_op = coalesce(c.lembrete_op, nullif(s.lembrete_op,'')::timestamptz),
  updated_at = now()
from stg_notion_clientes s
where s.cpf_n is null and s.phone_t is not null
  and right(regexp_replace(coalesce(c.phone_number,''),'\D','','g'),10) = s.phone_t;

-- ===== 4. CRIAR novos contatos (Notion sem match no banco) =====
select 1, s.nome, s.phone_full, s.cpf, s.rg, nullif(s.exp_rg,'')::date, nullif(s.data_nasc,'')::date, s.nome_mae, s.nome_pai, s.esp_benef, s.nb_mat, s.orgao_siape, s.recebimento_beneficio, s.banco, s.agencia, s.conta, s.nome_rep_legal, s.cpf_rep_legal, nullif(s.data_nasc_rl,'')::date, s.rua, s.numero, s.bairro, s.cidade, s.uf, s.cep, nullif(s.lembrete_op,'')::timestamptz, s.contexto_conversa, s.resumo_emprestimos, s.email, s.qualificacao, s.aquisicao, s.convenio, s.status, now(), now()
from stg_notion_clientes s
where not exists (
    select 1 from contacts c
    where s.cpf_n is not null and regexp_replace(coalesce(c.cpf,''),'\D','','g') = s.cpf_n)
  and not exists (
    select 1 from contacts c
    where s.phone_t is not null and right(regexp_replace(coalesce(c.phone_number,''),'\D','','g'),10) = s.phone_t);

-- ===== 5. relatorio =====
select
 (select count(*) from contacts) as total_contacts,
 (select count(*) from contacts where rg is not null and rg<>'') as com_rg,
 (select count(*) from contacts where nb_mat is not null and nb_mat<>'') as com_nb_mat;

